&lt;p&gt;दिए गए विकल्पों में सही उत्तर &lt;strong&gt;विकल्प&lt;/strong&gt;&lt;strong&gt; 4 &amp;lsquo;&lt;/strong&gt;&lt;strong&gt;तट&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;हाशिया&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;सिरा&lt;/strong&gt;&lt;strong&gt;&amp;rsquo; &lt;/strong&gt;हैं। अन्य विकल्प इसके अनुचित उत्तर हैं।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&amp;#39;तट, हाशिया, सिरा&amp;#39; शब्द &amp;#39;किनारा&amp;rsquo; के अनेकार्थी शब्द हैं। &amp;lsquo;किनारा&amp;rsquo; के अन्य शब्द हैं- पार्श्व आदि।&lt;/li&gt;
	&lt;li&gt;मौत, समय ये अन्य शब्द &amp;lsquo;काल&amp;rsquo; के अनेकार्थी शब्द हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;width:400px;&quot; width=&quot;445&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:67px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;शब्द&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:252px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;परिभाषा&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:126px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;उदाहरण&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:67px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;अनेकार्थी&lt;/strong&gt; &lt;strong&gt;शब्द&lt;/strong&gt;&amp;nbsp;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:252px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;जिन शब्दों के एक से अधिक अर्थ होते हैं, उन्हें &amp;#39;अनेकार्थी शब्द&amp;#39; कहते है।&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:126px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;काक- कौआ, लँगड़ा आदमी, अतिधृष्ट।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&amp;#39;हिमाद्रि&amp;#39; का पर्यायवाची शब्द &lt;/span&gt;&lt;u&gt;&lt;strong&gt;हिमालय​&lt;/strong&gt;&lt;/u&gt;&lt;span style=&quot;&quot;&gt;&lt;u&gt;&lt;strong&gt; &lt;/strong&gt;&lt;/u&gt;है।&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;b&gt;हिमालय &lt;/b&gt;के अन्य पर्यायवाची शब्द-&lt;b&gt;&amp;nbsp;&lt;/b&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;b&gt;​&lt;/b&gt;&lt;span style=&quot;&quot;&gt;हिमगिरी, हिमाचल, गिरिराज, पर्वतराज, &lt;span style=&quot;&quot;&gt;नगपति, हिमपति, नगराज, &lt;strong&gt;हिमाद्रि&lt;/strong&gt;, नगेश आदि।&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;अन्य विकल्प-&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;पर्वत &lt;/strong&gt;के&lt;strong&gt;&amp;nbsp;&lt;/strong&gt;पर्यायवाची शब्द-&lt;strong&gt;&amp;nbsp;&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;&quot;&gt;पहाड़, महीधर, शिखर, धरणीधर, गिरि,&lt;/span&gt; शैल,&amp;nbsp;अचल, नग, धराधर, गिरिराज, भूमिधर और भूभृत आदि।&amp;nbsp;&lt;span style=&quot;&quot;&gt; &lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;शैल&lt;/strong&gt;, &lt;u&gt;पर्वत &lt;/u&gt;का पर्यायवाची शब्द है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;हिम &lt;/strong&gt;के&amp;nbsp;पर्यायवाची शब्द-
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;&quot;&gt;आइस, तुषार, तुहिन, निहार, निहार,&amp;nbsp;&lt;span style=&quot;&quot;&gt;प्रालेय, बरफ, बरफ़, बर्फ, बर्फ़, महिका आदि।&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;पर्यायवाची शब्द-&amp;nbsp;&lt;/strong&gt;&lt;/span&gt;

	&lt;ul&gt;
		&lt;li&gt;ऐसे शब्द जिनके समान अर्थ हों।&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;सही विकल्प&amp;nbsp;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;विभाव&amp;nbsp;&lt;/strong&gt;है।&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;&amp;#39;आलंबन&amp;#39;&lt;/strong&gt;&amp;nbsp;विभाव&amp;nbsp;कहलाता है।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;आलंबन विभाव-&lt;/strong&gt; भावों का उद्गम जिस मुख्य भाव या वस्तु के कारण हो वह काव्य का आलंबन कहा जाता है।&lt;/li&gt;
	&lt;li&gt;जैसे शृंगार रस में नायक और नायिका &amp;quot;रति&amp;quot; संज्ञक स्थाई भाव के आलंबन होते हैं&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;आलंबन विभाव दो प्रकार के होते हैं&amp;nbsp;- विषय&lt;/strong&gt; और &lt;strong&gt;आश्रय&lt;/strong&gt;।&lt;span style=&quot;&quot;&gt;&amp;nbsp;&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;विषय -&lt;/strong&gt;&amp;nbsp;&lt;/span&gt;जिस पात्र के प्रति किसी पात्र के भाव जागृत होते हैं वह विषय है। साहित्य शास्त्र में इस विषय को आलंबन विभाव अथवा &amp;#39;आलंबन&amp;#39; कहते हैं।&amp;nbsp;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;आश्रय -&lt;/strong&gt;&amp;nbsp;&lt;/span&gt;जिस पात्र में भाव जागृत होते हैं वह आश्रय कहलाता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;अन्य विकल्प-&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;अनुभाव- &lt;/strong&gt;रति, हास, शोक आदि स्थायी भावों को प्रकाशित या व्यक्त करने वाली आश्रय की चेष्टाएं अनुभाव कहलाती हैं।&lt;/li&gt;
	&lt;li&gt;ये चेष्टाएं भाव-जागृति के उपरांत आश्रय में उत्पन्न होती हैं इसलिए इन्हें अनुभाव कहते हैं, अर्थात जो भावों का अनुगमन करे वह अनुभाव कहलाता है।
	&lt;ul&gt;
		&lt;li&gt;अनुभाव के दो भेद हैं - इच्छित और अनिच्छित।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;स्थायीभाव-&lt;/strong&gt;&amp;nbsp;सहृदय के हृदय में जो भाव स्थायी रूप से निवास करते हैं, स्थायी भाव कहलाते हैं। इन्हें अनुकूल या प्रतिकूल किसी प्रकार के भाव दबा नहीं पाते। स्थायी भाव नौ हैं। इन्हीं के आधार पर नौ रस माने गए हैं। प्रत्येक रस का एक स्थायी भाव नियत होता है।
	&lt;ul&gt;
		&lt;li&gt;रति, हास, शोक, उत्साह, क्रोध, भय, जुगुप्सा (घृणा), विस्मय, शम (निर्वेद) स्थायी भाव है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;संचारीभाव-&amp;nbsp;&lt;/strong&gt;स्थायी भाव को पुष्ट करने के लिए जो भाव उत्पन्न होकर पुनः लुप्त हो जाते हैं उन्हें संचारी भाव कहते हैं।
	&lt;ul&gt;
		&lt;li&gt;इनकी संख्या 33 मानी गई है। निर्वेद, शंका, ग्लानि, हर्ष, आवेग आदि प्रमुख संचारी भाव हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;&amp;#39;निशा-निमंत्रण&amp;#39; &lt;/strong&gt;के रचयिता हैं- &lt;strong&gt;&lt;u&gt;&amp;#39;हरिवंश राय बच्चन&amp;#39;&lt;/u&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&amp;#39;निशा निमंत्रण&amp;#39; &lt;strong&gt;हरिवंशराय बच्चन&lt;/strong&gt; के गीतों का संकलन है,&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;13-13&lt;/strong&gt; पंक्तियों के ये गीत हिन्दी साहित्य की श्रेष्ठतम उपलब्धियों में से हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;निशा-निमंत्रण-&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;रचनाकार-&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;&quot;&gt;हरिवंश राय बच्चन&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;विधा-&amp;nbsp;&lt;/span&gt;कविता&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;प्रकाशन वर्ष-&amp;nbsp;&lt;/span&gt;1938 ई.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/mistake-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Mistake Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;महादेवी वर्मा-&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;जन्म-&amp;nbsp;&lt;/span&gt;1907-1987 ई.&lt;/li&gt;
	&lt;li&gt;हिन्दी&amp;nbsp;भाषा की कवयित्री थीं।&lt;/li&gt;
	&lt;li&gt;वे&amp;nbsp;हिन्दी साहित्य&amp;nbsp;में&amp;nbsp;छायावादी युग&amp;nbsp;के चार प्रमुख स्तम्भों&amp;nbsp;में से एक मानी जाती हैं।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;काव्य&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;संग्रह-&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;नीहार (1930&amp;nbsp;ई.)&lt;/li&gt;
		&lt;li&gt;रश्मि (1932&amp;nbsp;ई.)&lt;/li&gt;
		&lt;li&gt;नीरजा (1934&amp;nbsp;ई.)&lt;/li&gt;
		&lt;li&gt;सांध्यगीत (1936&amp;nbsp;ई.)&lt;/li&gt;
		&lt;li&gt;दीपशिखा (1942&amp;nbsp;ई.)&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;श्यामनारायण पाण्डेय:-&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;जन्म-&amp;nbsp;&lt;/span&gt;1907-1991&amp;nbsp;&lt;span style=&quot;&quot;&gt;ई.&lt;/span&gt;&lt;/li&gt;
	&lt;li style=&quot;&quot;&gt;यह&amp;nbsp;वीर रस के सुविख्यात हिन्दी कवि थे।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;काव्य&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;संग्रह-&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;हल्दी घाटी&amp;nbsp;(1937-39 ई.)&lt;/li&gt;
		&lt;li&gt;जौहर&amp;nbsp;(1939-44 ई.)&lt;/li&gt;
		&lt;li&gt;तुमुल&amp;nbsp;(1948 ई.)&amp;nbsp;&lt;/li&gt;
		&lt;li&gt;रूपांतर&amp;nbsp;(1948 ई.)&lt;/li&gt;
		&lt;li&gt;जय हनुमान&amp;nbsp;(1956 ई.)&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;जयशंकर प्रसाद-&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;जन्म-&lt;/span&gt;1889-1937 ई.&lt;/li&gt;
	&lt;li&gt;हिन्दी कवि, नाटककार, कहानीकार, उपन्यासकार तथा निबन्ध-लेखक थे।&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;वे हिन्दी के&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;छायावादी युग&lt;/span&gt;&amp;nbsp;के चार प्रमुख स्तंभों में से एक हैं।&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;काव्य संग्रह-&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;प्रेम-पथिक (1909&amp;nbsp;ई.)&lt;/li&gt;
		&lt;li&gt;कानन कुसुम (1913 ई.)&lt;/li&gt;
		&lt;li&gt;झरना (1918&amp;nbsp;ई.)&lt;/li&gt;
		&lt;li&gt;आँसू (1924&amp;nbsp;ई.)&lt;/li&gt;
		&lt;li&gt;लहर&amp;nbsp;(1935&amp;nbsp;ई.)&lt;/li&gt;
		&lt;li&gt;कामायनी (1936 ई.)&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

