&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color: rgb(33, 37, 41);&quot;&gt;
	&lt;li&gt;ऐसे शब्द जो समय के साथ संस्कृत से विकृत हो कर हिंदी में प्रयोग किये जाते हैं उन्हें ही&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;तद्भव शब्द&lt;/span&gt;&amp;nbsp;कहते हैं।&lt;/li&gt;
	&lt;li&gt;तद्भव का अर्थ है&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;तद् + भव&lt;/span&gt;&amp;nbsp;अर्थात &amp;lsquo;&lt;span style=&quot;font-weight: bolder;&quot;&gt;ऐसा हो गया&lt;/span&gt;&amp;rsquo;।&amp;nbsp;
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;जैसे&lt;/span&gt;&amp;nbsp;- आग, घोड़ा, कबूतर, लोहा।&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;ऐसे शब्द जो&amp;nbsp;संस्कृत से बिना किसी परिवर्तन के लिए जाते हैं, उन्हें ही&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;तत्सम शब्द&lt;/span&gt;&amp;nbsp;कहते हैं।&lt;/li&gt;
	&lt;li&gt;तत्सम का अर्थ है&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;तत् + सम&lt;/span&gt;&amp;nbsp;अर्थात &amp;lsquo;&lt;span style=&quot;font-weight: bolder;&quot;&gt;ऐसा था&lt;/span&gt;&amp;rsquo;।&amp;nbsp;
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;जैसे&lt;/span&gt;&amp;nbsp;- वायु, धोनु, हरि, पत्र, राजा, अग्नि, सूर्य आदि।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;सही&amp;nbsp;उत्तर&lt;strong&gt;&amp;nbsp;&amp;#39;अव्यय&amp;#39;&lt;/strong&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&amp;quot;तुम यहीं बैठो।&amp;quot; इसमें &amp;#39;यहीं&amp;#39; अव्यय&amp;nbsp;हैI&lt;/li&gt;
	&lt;li&gt;अव्यय&amp;nbsp;शब्द&amp;nbsp;-&amp;nbsp;अव्यय शब्दों को अविकारी शब्द भी कहते हैं क्योंकि इनमें लिंग, कारक, वचन, पुरुष आदि के कारण कोई विकार/ परिवर्तन उत्पन्न नहीं होता है। जैसे &amp;ndash; आज, कब, इधर, किन्तु आदि।&amp;nbsp;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;समुच्चयबोधक शब्दों को योजक भी कहा जाता हैI&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;जिन शब्दों की वजह से दो या दो से ज्यादा वाक्य, शब्द या वाक्यांश जुड़ते हैं उन्हें समुच्चयबोधक कहा जाता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;जैसे&lt;/strong&gt;- राम और सीता वन को गए।, तुम चलोगे तो मैं चलूँगा।&amp;#39;समुच्चयबोधक अव्यय&amp;#39; अव्यय का एक भेद हैI&lt;/li&gt;
	&lt;li&gt;सर्वनाम वे शब्द होते हैं जो संज्ञा के स्थान पर प्रयोग किये जाते हैं।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;जैसे &lt;/strong&gt;- तू, तुम, वे आदि।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;संज्ञा -&lt;/strong&gt; किसी प्राणी, वस्तु, स्थान, गुण या भाव के नाम को संज्ञा कहते है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;जैसे - &lt;/strong&gt;पशु (जाति), सुन्दरता (गुण), व्यथा (भाव), मोहन (व्यक्ति), दिल्ली (स्थान), मारना (क्रिया)।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;दिए गए विकल्पों में से सही उत्तर &lt;strong&gt;विकल्प 3&amp;nbsp;&lt;/strong&gt;&lt;strong&gt;&amp;lsquo;भाववाच्य&amp;rsquo;&lt;/strong&gt; है। अन्य विकल्प इसके गलत उत्तर हैं।&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;दिए गए विकल्पों में बैठा नहीं जा रहा है।&amp;#39; यह वाक्य भाववाच्य का है।&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;जहां भाव की प्रधानता हो तथा क्रिया का लिंग, वचन, भाव के लिंग, के वचन के अनुरूप हो, तो क्रिया का ऐसा रूपांतर &amp;#39;भाववाच्य&amp;#39; कहलाता है।&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;width:400px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td colspan=&quot;3&quot; style=&quot;width:423px;height:49px;&quot;&gt;
			&lt;p style=&quot;text-align: justify;&quot;&gt;&lt;strong&gt;वाच्य- &lt;/strong&gt;क्रिया के जिस रूपांतर से यह जाना जाता है कि क्रिया का विधान कर्ता, कर्म या भाव में से किससे या किसके विषय में किया गया है, वाच्य कहलाता है। हिंदी में वाच्य तीन प्रकार के होते हैं-&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:73px;height:35px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;कर्तृवाच्य&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:199px;height:35px;&quot;&gt;
			&lt;p style=&quot;text-align: justify;&quot;&gt;इस वाच्य में कर्ता के लिंग, वचन और पुरुष के अनुसार क्रिया का प्रयोग होता है।&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:151px;height:35px;&quot;&gt;
			&lt;p style=&quot;text-align: justify;&quot;&gt;रमेश केला खाता है।&lt;/p&gt;

			&lt;p&gt;लड़का पुस्तक पढ़ता है।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:73px;height:35px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;कर्मवाच्य&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:199px;height:35px;&quot;&gt;
			&lt;p style=&quot;text-align: justify;&quot;&gt;क्रिया के उस रूपान्तर को कर्मवाच्य कहते हैं, जिससे वाक्य में कर्म की प्रधानता का बोध हो।&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:151px;height:35px;&quot;&gt;
			&lt;p style=&quot;text-align: justify;&quot;&gt;रोगी को दवा दी गई।&lt;/p&gt;

			&lt;p style=&quot;text-align: justify;&quot;&gt;उसके द्वारा पुस्तक पढ़ी गई।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:73px;height:35px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;भाववाच्य&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:199px;height:35px;&quot;&gt;
			&lt;p style=&quot;text-align: justify;&quot;&gt;क्रिया के जिस रूप में न तो कर्ता की प्रधानता हो न कर्म की बल्कि क्रिया का भाव ही प्रधान हो, वहाँ भाववाच्य होता है।&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:151px;height:35px;&quot;&gt;
			&lt;p style=&quot;text-align: justify;&quot;&gt;राम से रेत में दौड़ा भी नहीं जाता। मुझसे उठा नहीं जाता।&amp;nbsp;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;सही उत्तर है - बुरे काम में पड़ने का नतीजा बदनामी।&amp;nbsp;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&amp;nbsp;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;lsquo;कोयले&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;की&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;दलाली&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;में&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;मुँह&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;काला&lt;/span&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;rsquo;&lt;/span&gt;&amp;nbsp;का अर्थ है&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;lsquo;&lt;/span&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;बुरों&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;के&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;साथ&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;बुराई&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;ही&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;मिलती&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;है&lt;/span&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;rsquo;&lt;/span&gt;।&lt;/li&gt;
	&lt;li style=&quot;color: rgb(33, 37, 41);&quot;&gt;अतः विकल्प&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;lsquo;&lt;/span&gt;&lt;strong&gt;बुरे काम में पड़ने का नतीजा बदनामी&lt;/strong&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;rsquo;&amp;nbsp;&lt;/span&gt;सही है।&lt;/li&gt;
	&lt;li style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&lt;u&gt;वाक्य&lt;/u&gt;&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&lt;u&gt;प्रयोग&lt;/u&gt;&lt;/span&gt;&amp;nbsp;- गलत काम हमें गर्त में ही ले जाता है, कोयले की दलाली में मुँह तो काला होना ही है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;लोकोक्ति:-&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&amp;#39;लोकोक्ति&amp;#39; शब्द &amp;#39;लोक + उक्ति&amp;#39; शब्दों से मिलकर बना है जिसका अर्थ है- लोक में प्रचलित उक्ति या कथन&amp;#39;। संस्कृत में &amp;#39;लोकोक्ति&amp;#39; अलंकार का एक भेद भी है तथा सामान्य अर्थ में लोकोक्ति को &amp;#39;कहावत&amp;#39; कहा जाता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;उदाहरण:-&lt;/strong&gt;&amp;nbsp;​
	&lt;ul&gt;
		&lt;li&gt;&amp;nbsp;&lt;/li&gt;
		&lt;li&gt;अंत भले का भला।&amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp;&amp;nbsp;&lt;/li&gt;
		&lt;li&gt;अढ़ाई दिन की बादशाहत।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&amp;lsquo;फलों के नाम&amp;rsquo;, &amp;lsquo;द्वीप के नाम&amp;rsquo; तथा &amp;lsquo;रत्नों के नाम&amp;rsquo; यह तीनों नाम सदा पुल्लिंग होते हैं। इस आधार पर हम कह सकते हैं कि &lt;strong&gt;उपर्युक्त&lt;/strong&gt; &lt;strong&gt;सभी&lt;/strong&gt; विकल्प सही हैं।&lt;/p&gt;

